
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';

function Login({setLogin}) {
    let [name, setName] = useState("");
    let [pass, setPass] = useState("");
    let navigate = useNavigate();
    //on click of login button we need to check credentialsid yes -> home page if no invalid credentials or again login page

    let getLogin = ()=>
    {
        if(name === "aanu" && pass === "1234")
        {
           console.log("Login successfully");
           setLogin(true);
           navigate("/");

        }
    }
  return (
    <div>
        Username : <input type="text" onChange={(e)=>setName(e.target.value)} />
        Password: <input type="password" onChange={(e)=>setPass(e.target.value)}/>
        <button onClick={getLogin}>Login</button>
    </div>
  )
}

export default Login